const button=document.querySelector(".header_burger-button"),nav=document.querySelector(".header_navigation");button.addEventListener("click",(()=>{nav.classList.toggle("--open"),button.classList.toggle("--burger-open")}));const slider=document.querySelector(".slide-list"),slides=document.querySelectorAll(".slide"),prevButton=document.querySelector(".--left"),nextButton=document.querySelector(".--right");let currentIndex=0;function updateSliderPosition(){const e=100*-currentIndex;slider.style.transform=`translateX(${e}%)`}function autoSlide(){currentIndex<slides.length-1?currentIndex++:currentIndex=0,updateSliderPosition()}prevButton.addEventListener("click",(()=>{currentIndex>0&&(currentIndex--,updateSliderPosition())})),nextButton.addEventListener("click",(()=>{currentIndex<slides.length-1&&(currentIndex++,updateSliderPosition())})),setInterval(autoSlide,3e3);